const markWaVoiceNoteFailed = `-- name: MarkWaVoiceNoteFailed :exec
UPDATE wa_voice_notes
SET attempts = attempts + 1,
    last_error = $2,
    next_attempt_at = $3,
    status = CASE WHEN attempts + 1 >= $4 THEN 'failed' ELSE 'pending' END
WHERE id = $1
`

type MarkWaVoiceNoteFailedParams struct {
	ID            string    `json:"id"`
	LastError     *string   `json:"last_error"`
	NextAttemptAt time.Time `json:"next_attempt_at"`
	MaxAttempts   int32     `json:"max_attempts"`
}

// Failure keeps the row 'pending' (retryable) until attempts reaches the cap,
// then flips it to the terminal 'failed'. next_attempt_at carries the
// caller-computed exponential backoff.
func (q *Queries) MarkWaVoiceNoteFailed(ctx context.Context, arg MarkWaVoiceNoteFailedParams) error {
	_, err := q.db.Exec(ctx, markWaVoiceNoteFailed,
		arg.ID,
		arg.LastError,
		arg.NextAttemptAt,
		arg.MaxAttempts,
	)
	return err
}

