const updateAgentWorkflow = `-- name: UpdateAgentWorkflow :one
UPDATE agents
SET name = $2, system_prompt = $3, greeting_message = $4, failure_message = $5,
    asr = $6, llm = $7, tts = $8, max_history = $9,
    mcp_servers = $11, skills = $12, sub_agents = $13,
    turn_detection = $14, start_of_speech = $15, end_of_speech = $16,
    selective_attention_locking = $17, filler_words = $18,
    clarification_rules = $19,
    last_published = CASE WHEN $10::text = 'published' AND status <> 'published' THEN NOW() ELSE last_published END,
    status = $10, last_edited = NOW()
WHERE id = $1
RETURNING id, name, project_id, hosting_region, status, last_edited, last_published, template, system_prompt, greeting_message, failure_message, model_type, asr, llm, tts, turn_detection, start_of_speech, end_of_speech, selective_attention_locking, filler_words, max_history, mcp_servers, skills, sub_agents, clarification_rules
`

type UpdateAgentWorkflowParams struct {
	ID                        string `json:"id"`
	Name                      string `json:"name"`
	SystemPrompt              string `json:"system_prompt"`
	GreetingMessage           string `json:"greeting_message"`
	FailureMessage            string `json:"failure_message"`
	Asr                       []byte `json:"asr"`
	Llm                       []byte `json:"llm"`
	Tts                       []byte `json:"tts"`
	MaxHistory                int32  `json:"max_history"`
	Status                    string `json:"status"`
	McpServers                []byte `json:"mcp_servers"`
	Skills                    []byte `json:"skills"`
	SubAgents                 []byte `json:"sub_agents"`
	TurnDetection             bool   `json:"turn_detection"`
	StartOfSpeech             bool   `json:"start_of_speech"`
	EndOfSpeech               bool   `json:"end_of_speech"`
	SelectiveAttentionLocking bool   `json:"selective_attention_locking"`
	FillerWords               bool   `json:"filler_words"`
	ClarificationRules        []byte `json:"clarification_rules"`
}

// last_published is stamped only on the draft->published transition (D4);
// the CASE reads the pre-update status, per UPDATE..SET semantics. The panel
// now edits the full five-block config, so every operator-editable column is set.
func (q *Queries) UpdateAgentWorkflow(ctx context.Context, arg UpdateAgentWorkflowParams) (Agent, error) {
	row := q.db.QueryRow(ctx, updateAgentWorkflow,
		arg.ID,
		arg.Name,
		arg.SystemPrompt,
		arg.GreetingMessage,
		arg.FailureMessage,
		arg.Asr,
		arg.Llm,
		arg.Tts,
		arg.MaxHistory,
		arg.Status,
		arg.McpServers,
		arg.Skills,
		arg.SubAgents,
		arg.TurnDetection,
		arg.StartOfSpeech,
		arg.EndOfSpeech,
		arg.SelectiveAttentionLocking,
		arg.FillerWords,
		arg.ClarificationRules,
	)
	var i Agent
	err := row.Scan(
		&i.ID,
		&i.Name,
		&i.ProjectID,
		&i.HostingRegion,
		&i.Status,
		&i.LastEdited,
		&i.LastPublished,
		&i.Template,
		&i.SystemPrompt,
		&i.GreetingMessage,
		&i.FailureMessage,
		&i.ModelType,
		&i.Asr,
		&i.Llm,
		&i.Tts,
		&i.TurnDetection,
		&i.StartOfSpeech,
		&i.EndOfSpeech,
		&i.SelectiveAttentionLocking,
		&i.FillerWords,
		&i.MaxHistory,
		&i.McpServers,
		&i.Skills,
		&i.SubAgents,
		&i.ClarificationRules,
	)
	return i, err
}

const updateSettings = `-- name: UpdateSettings :exec
UPDATE settings
SET tts_model = $1, model_ids = $2, default_speed = $3, bot_config = $4, assistant_agent_id = $5
WHERE id = 1
`

type UpdateSettingsParams struct {
	TtsModel         string  `json:"tts_model"`
	ModelIds         []byte  `json:"model_ids"`
	DefaultSpeed     float32 `json:"default_speed"`
	BotConfig        []byte  `json:"bot_config"`
	AssistantAgentID *string `json:"assistant_agent_id"`
}

func (q *Queries) UpdateSettings(ctx context.Context, arg UpdateSettingsParams) error {
	_, err := q.db.Exec(ctx, updateSettings,
		arg.TtsModel,
		arg.ModelIds,
		arg.DefaultSpeed,
		arg.BotConfig,
		arg.AssistantAgentID,
	)
	return err
}

const updateWaContactSettings = `-- name: UpdateWaContactSettings :one
UPDATE wa_contacts
SET enabled = $2, agent_id = $3, updated_at = NOW()
WHERE chat_id = $1
RETURNING chat_id, name, enabled, agent_id, prompt_override, updated_at, erp_uid, erp_display_name, erp_org_id, erp_role, erp_unresolved_reason, erp_resolved_at, erp_phone_override
`

type UpdateWaContactSettingsParams struct {
	ChatID  string  `json:"chat_id"`
	Enabled bool    `json:"enabled"`
	AgentID *string `json:"agent_id"`
}

func (q *Queries) UpdateWaContactSettings(ctx context.Context, arg UpdateWaContactSettingsParams) (WaContact, error) {
	row := q.db.QueryRow(ctx, updateWaContactSettings, arg.ChatID, arg.Enabled, arg.AgentID)
	var i WaContact
	err := row.Scan(
		&i.ChatID,
		&i.Name,
		&i.Enabled,
		&i.AgentID,
		&i.PromptOverride,
		&i.UpdatedAt,
		&i.ErpUid,
		&i.ErpDisplayName,
		&i.ErpOrgID,
		&i.ErpRole,
		&i.ErpUnresolvedReason,
		&i.ErpResolvedAt,
		&i.ErpPhoneOverride,
	)
	return i, err
}

const upsertConversationState = `-- name: UpsertConversationState :exec
INSERT INTO conversation_state (chat_id, summary, summarized_through, updated_at)
VALUES ($1, $2, $3, NOW())
ON CONFLICT (chat_id) DO UPDATE
SET summary = EXCLUDED.summary, summarized_through = EXCLUDED.summarized_through, updated_at = NOW()
`

type UpsertConversationStateParams struct {
	ChatID            string `json:"chat_id"`
	Summary           string `json:"summary"`
	SummarizedThrough int64  `json:"summarized_through"`
}

func (q *Queries) UpsertConversationState(ctx context.Context, arg UpsertConversationStateParams) error {
	_, err := q.db.Exec(ctx, upsertConversationState, arg.ChatID, arg.Summary, arg.SummarizedThrough)
	return err
}

const upsertPendingConfirmation = `-- name: UpsertPendingConfirmation :exec
INSERT INTO pending_confirmations (chat_id, tool_id, args, org_id, acting_user_uid, description, status, claimed_at, created_at, expires_at, missing_fields, collect_rounds, intent)
VALUES ($1, $2, $3, $4, $5, $6, 'pending', NULL, NOW(), $7, '[]'::jsonb, 0, '')
ON CONFLICT (chat_id) DO UPDATE
SET tool_id = EXCLUDED.tool_id, args = EXCLUDED.args, org_id = EXCLUDED.org_id,
    acting_user_uid = EXCLUDED.acting_user_uid, description = EXCLUDED.description,
    status = 'pending', claimed_at = NULL,
    created_at = NOW(), expires_at = EXCLUDED.expires_at,
    missing_fields = '[]'::jsonb, collect_rounds = 0, intent = ''
`

type UpsertPendingConfirmationParams struct {
	ChatID        string    `json:"chat_id"`
	ToolID        string    `json:"tool_id"`
	Args          []byte    `json:"args"`
	OrgID         string    `json:"org_id"`
	ActingUserUid string    `json:"acting_user_uid"`
	Description   string    `json:"description"`
	ExpiresAt     time.Time `json:"expires_at"`
}

func (q *Queries) UpsertPendingConfirmation(ctx context.Context, arg UpsertPendingConfirmationParams) error {
	_, err := q.db.Exec(ctx, upsertPendingConfirmation,
		arg.ChatID,
		arg.ToolID,
		arg.Args,
		arg.OrgID,
		arg.ActingUserUid,
		arg.Description,
		arg.ExpiresAt,
	)
	return err
}

const upsertCollecting = `-- name: UpsertCollecting :exec
INSERT INTO pending_confirmations (chat_id, tool_id, args, org_id, acting_user_uid, description, status, claimed_at, created_at, expires_at, missing_fields, collect_rounds, intent)
VALUES ($1, $2, $3, $4, $5, $6, 'collecting', NULL, NOW(), $7, $8, $9, $10)
ON CONFLICT (chat_id) DO UPDATE
SET tool_id = EXCLUDED.tool_id, args = EXCLUDED.args, org_id = EXCLUDED.org_id,
    acting_user_uid = EXCLUDED.acting_user_uid, description = EXCLUDED.description,
    status = 'collecting', claimed_at = NULL,
    created_at = NOW(), expires_at = EXCLUDED.expires_at,
    missing_fields = EXCLUDED.missing_fields, collect_rounds = EXCLUDED.collect_rounds,
    intent = EXCLUDED.intent
`

type UpsertCollectingParams struct {
	ChatID        string    `json:"chat_id"`
	ToolID        string    `json:"tool_id"`
	Args          []byte    `json:"args"`
	OrgID         string    `json:"org_id"`
	ActingUserUid string    `json:"acting_user_uid"`
	Description   string    `json:"description"`
	ExpiresAt     time.Time `json:"expires_at"`
	MissingFields []byte    `json:"missing_fields"`
	CollectRounds int32     `json:"collect_rounds"`
	Intent        string    `json:"intent"`
}

// UpsertCollecting parks a tool call that is still missing required args
// (F-1 fix). Mirrors UpsertPendingConfirmation's upsert shape exactly, but
// with status='collecting' and the extra slot-filling columns populated.
func (q *Queries) UpsertCollecting(ctx context.Context, arg UpsertCollectingParams) error {
	_, err := q.db.Exec(ctx, upsertCollecting,
		arg.ChatID,
		arg.ToolID,
		arg.Args,
		arg.OrgID,
		arg.ActingUserUid,
		arg.Description,
		arg.ExpiresAt,
		arg.MissingFields,
		arg.CollectRounds,
		arg.Intent,
	)
	return err
}

const upsertWaVoiceNote = `-- name: UpsertWaVoiceNote :exec

INSERT INTO wa_voice_notes (id, chat_id, direction, sender, receiver, object_path, mime_type, size_bytes, duration_seconds, status)
VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9, 'pending')
ON CONFLICT (id) DO NOTHING
`

type UpsertWaVoiceNoteParams struct {
	ID              string `json:"id"`
	ChatID          string `json:"chat_id"`
	Direction       string `json:"direction"`
	Sender          string `json:"sender"`
	Receiver        string `json:"receiver"`
	ObjectPath      string `json:"object_path"`
	MimeType        string `json:"mime_type"`
	SizeBytes       int64  `json:"size_bytes"`
	DurationSeconds int32  `json:"duration_seconds"`
}

// Voice-note archive (Firebase Cloud Storage ledger) ------------------------
// ON CONFLICT DO NOTHING makes enqueueing idempotent: re-processing the same
// WhatsApp message never creates a second upload job.
func (q *Queries) UpsertWaVoiceNote(ctx context.Context, arg UpsertWaVoiceNoteParams) error {
	_, err := q.db.Exec(ctx, upsertWaVoiceNote,
		arg.ID,
		arg.ChatID,
		arg.Direction,
		arg.Sender,
		arg.Receiver,
		arg.ObjectPath,
		arg.MimeType,
		arg.SizeBytes,
		arg.DurationSeconds,
	)
	return err
}
